    {
        "@context": "https://schema.org",
        "@type": "DefinedTermSet",
        "name": "Pvt to Public Ltd Conversion Key Terms",
        "definedTerm": [
            {
                "@type": "DefinedTerm",
                "name": "Section 14 Companies Act 2013",
                "description": "Charging section for alteration of Articles including the alteration that converts a Private Company into a Public Company; the proviso requiring Central Government approval applies only to the reverse direction (Public to Private)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 18 Companies Act 2013",
                "description": "Recognises conversion of companies already registered as a change of company type that preserves the body corporate; assets, liabilities, contracts and proceedings carry forward."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 2(71) Public Company Definition",
                "description": "A company which is not a private company; includes a subsidiary of a public company (deemed public). Shareholder base unlimited; share transfers free; public invitation for securities permitted (subject to SEBI for listed)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 3 - Minimum Members",
                "description": "Minimum 7 members for a Public Limited Company (versus 2 for Pvt Ltd and 1 for OPC); maximum unlimited."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 149 - Directors",
                "description": "Minimum 3 directors for a Public Limited Company (versus 2 for Pvt Ltd); at least 1 must be an Indian resident under Section 149(3)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 149(4) - Independent Directors",
                "description": "Mandatory for listed Public Companies; for unlisted Public Companies - applicable above thresholds of INR 10 crore paid-up share capital, INR 100 crore turnover or INR 50 crore aggregate outstanding loans / debentures / deposits."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 177 - Audit Committee",
                "description": "Mandatory for listed Public Companies and unlisted Public Companies above the same thresholds as independent directors; chaired by an independent director."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 178 - Nomination and Remuneration Committee",
                "description": "Mandatory for listed Public Companies and unlisted Public Companies above the same thresholds; minimum 3 non-executive directors with majority independent."
            },
            {
                "@type": "DefinedTerm",
                "name": "Rule 33 Companies (Incorporation) Rules 2014",
                "description": "Procedural rule prescribing Form INC-27 filing for Pvt-to-Public conversion within 15 days of the special resolution."
            },
            {
                "@type": "DefinedTerm",
                "name": "Form MGT-14",
                "description": "Filing of special resolution with ROC within 30 days under Section 117; required for any alteration of MOA or AOA."
            },
            {
                "@type": "DefinedTerm",
                "name": "Form INC-27",
                "description": "Application for conversion - filed within 15 days of the special resolution under Rule 33; ROC issues a fresh Certificate of Incorporation upon acceptance."
            },
            {
                "@type": "DefinedTerm",
                "name": "Special Resolution",
                "description": "A resolution requiring 75 percent (three-fourths) majority of members present and voting at a properly convened general meeting with 21 clear days of notice (Section 114(2))."
            }
        ]
